const HEROES_USSR = [
{name:"Банкузов Анатолий Иванович",photo:"images/heroes_ussr/bankuzov.jpg",rank:"Герой Советского Союза",bio:"Родился 15 января 1917 года в деревне Мхиничи Могилёвской области. В 1940 году окончил Саратовское военное училище НКВД СССР. Участник войны с июня 1941 года. Сражался на Карельском, Западном, Брянском, Калининском, 1-м и 2-м Прибалтийских и 3-м Белорусском фронтах.\n\n6 февраля 1944 года назначен командиром 17-го гвардейского стрелкового полка. Полк отличился при штурме города-крепости Пиллау и при форсировании пролива Зеетиф. Действия полка способствовали капитуляции более 6000 немецких солдат и офицеров.\n\nЗвание «генерал-майор» присвоено в 1953 году. Награждён 2 орденами Ленина, 3 орденами Красного Знамени, орденами Суворова и Кутузова 3-й степени.\n\nУказом Президиума Верховного Совета СССР от 5 мая 1945 года присвоено звание Героя Советского Союза."},
{name:"Богомолов Александр Федорович",photo:"images/heroes_ussr/bogomolv.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился 27 августа 1919 года в селе Добрынское Владимирской области. В 1942 году окончил Саратовское военное училище НКВД СССР. К январю 1945 года командовал 3-м стрелковым батальоном 1050-го стрелкового полка 1-го Белорусского фронта.\n\nВ ночь с 14 на 15 января 1945 года батальон переправился через реку Пилица, захватил плацдарм и отражал контратаки танковых и пехотных сил. Когда противник вклинился в оборону, Богомолов с автоматчиками отразил атаку, лично уничтожив 3 солдат.\n\nПринимал участие в форсировании Одера. 5 февраля 1945 года скончался от ранений.\n\nУказом Президиума Верховного Совета СССР от 27 февраля 1945 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Дилигей Николай Куприянович",photo:"images/heroes_ussr/diligey.jpg",rank:"Герой Советского Союза",bio:"Родился 24 октября 1911 года в селе Комины Хмельницкой области. Окончил 4-ю Саратовскую школу пограничной и внутренней охраны войск ОГПУ, затем авиационное отделение Харьковского военного училища НКВД. Служил на советско-китайской границе.\n\nК февралю 1944 года майор Дилигей командовал 508-м истребительным авиаполком 5-й воздушной армии 2-го Украинского фронта.\n\nУказом Президиума Верховного Совета СССР от 1 июля 1944 года присвоено звание Героя Советского Союза."},
{name:"Довженко Виктор Михайлович",photo:"images/heroes_ussr/dovzhenko.jpg",rank:"Герой Советского Союза",bio:"Родился 3 марта 1920 года в селе Ташла Оренбургской области. В 1942 году окончил курсы младших лейтенантов Саратовского военного училища НКВД СССР. С февраля 1943 года — на фронтах Великой Отечественной войны. Участвовал в Курской битве, освобождении Украинской и Белорусской ССР.\n\n15 января 1945 года группа автоматчиков во главе с Довженко проникла во вражеский тыл, разгромила большую группу вражеских солдат. Рота первой переправилась через Вислу и захватила плацдарм на западном берегу.\n\nОрден Ленина и медаль «Золотая Звезда» он получить не успел — погиб в бою 4 марта 1945 года.\n\nУказом Президиума Верховного Совета СССР от 27 февраля 1945 года присвоено звание Героя Советского Союза."},
{name:"Ерошин Александр Матвеевич",photo:"images/heroes_ussr/eroshin.jpg",rank:"Герой Советского Союза",bio:"Родился 23 августа 1923 года в деревне Хворостянка Орловской области. В 1942 году окончил Горьковское танковое училище. Командир танка Т-34 в ночь на 17 февраля 1943 года первым проник в тыл противника в районе Матвеева Кургана и не дал врагу взорвать железнодорожный мост. Экипаж уничтожил более роты противника.\n\nВ 1947 году окончил Военную академию бронетанковых войск. Работал старшим преподавателем в Саратовском военном училище МГБ СССР.\n\nУказом Президиума Верховного Совета СССР от 28 апреля 1943 года присвоено звание Героя Советского Союза."},
{name:"Зенин Илларион Степанович",photo:"images/heroes_ussr/zenin.jpg",rank:"Герой Советского Союза",bio:"Родился 29 августа 1916 года в селе Красное Знамя Саратовской области. В 1941 году окончил Саратовское военное училище НКВД. Участвовал в боях под Ленинградом, обороне Шлиссельбурга, прорыве блокады. Три раза ранен и контужен.\n\nНочью 10 июня 1944 года скрытно выдвинул батальон, первым в дивизии переправился через реку и пошёл на штурм укреплений. За первый час вклинился в оборону на 4 километра.\n\nУказом Президиума Верховного Совета СССР от 21 июля 1944 года присвоено звание Героя Советского Союза."},
{name:"Кирдищев Гавриил Федотович",photo:"images/heroes_ussr/kirdishchev.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился 20 марта 1919 года в селе Приозёрное в Казахстане. В 1942 году окончил курсы младших лейтенантов Саратовского военного училища войск НКВД.\n\n1 июля 1944 года застава из 30 человек вступила в бой с вражеской ротой: 34 гитлеровца уничтожено, 24 взяты в плен. 13 июля принял бой с отрядом до 300 человек. Подпустив противника на 50–70 метров, пограничники обрушили шквальный огонь и поднялись в контратаку. Командир был тяжело ранен и скончался от ранения.\n\nУказом Президиума Верховного Совета СССР от 24 марта 1945 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Козорезов Андрей Акимович",photo:"images/heroes_ussr/kozorezov.jpg",rank:"Герой Советского Союза",bio:"Родился 26 октября 1918 года в деревне Останкова Курской области. Служил в пограничных войсках НКВД. Особо отличился 15 октября 1943 года при форсировании Днепра у посёлка Лоев. Взвод под его командованием в числе первых преодолел реку под огнём противника.\n\nВ 1945 году окончил курсы младших лейтенантов при Саратовском военном училище войск НКВД.\n\nУказом Президиума Верховного Совета СССР от 30 октября 1943 года присвоено звание Героя Советского Союза."},
{name:"Константинов Александр Константинович",photo:"images/heroes_ussr/konstantinov.jpg",rank:"Герой Советского Союза",bio:"Родился 9 марта 1910 года в деревне Зинаидово Тверской области. В пограничных войсках ОГПУ НКВД с 1932 года. В 1937 году окончил Саратовское военное училище НКВД СССР. Был командиром самой западной заставы Советского Союза в Перемышле.\n\n22 июня 1941 года принял на себя руководство обороной пограничной заставы № 5 у города Кагул (Молдавия). В течение дня застава отразила одиннадцать атак противника. 24 июня отбил у врага железнодорожный мост через реку Прут, лично уничтожив два пулемётных расчёта.\n\nУказом Президиума Верховного Совета СССР от 26 августа 1941 года присвоено звание Героя Советского Союза."},
{name:"Кузнецов Иван Иванович",photo:"images/heroes_ussr/kuznetsov_ii.jpg",rank:"Герой Советского Союза",bio:"Родился 14 января 1908 года в деревне Наводово Архангельской области. В 1934 году окончил 4-ю школу пограничной и внутренней охраны НКВД, в 1941 году — Военную академию имени М. В. Фрунзе. Участвовал в обороне Лиепаи, Таллина.\n\nС июля 1944 года командовал 413-м стрелковым полком. 4 сентября 1944 года полк прорвал немецкую оборону на берегу реки Нарев и захватил плацдарм.\n\nНаграждён 2 орденами Ленина, 4 орденами Красного Знамени.\n\nУказом Президиума Верховного Совета СССР от 24 марта 1945 года присвоено звание Героя Советского Союза."},
{name:"Кузнецов Степан Никифорович",photo:"images/heroes_ussr/kuznetsov_sn.jpg",rank:"Герой Советского Союза",bio:"Родился 26 ноября 1918 года в деревне Бажениха Удмуртской Республики. В 1938 году призван в пограничные войска НКВД. Наводчик орудия 63-го отдельного истребительно-противотанкового дивизиона. 15 октября 1943 года переправился через Днепр в районе посёлка Лоев и принял участие в боях за плацдарм.\n\nВ 1945 году окончил курсы младших лейтенантов в Саратовском военном училище войск НКВД.\n\nУказом Президиума Верховного Совета СССР от 30 октября 1943 года присвоено звание Героя Советского Союза."},
{name:"Лопатин Алексей Васильевич",photo:"images/heroes_ussr/lopatin.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился 15 февраля 1915 в селе Дюково Ивановской области. В 1940 году окончил Саратовское военное училище НКВД. Начальник 13-й пограничной заставы 90-го Владимир-Волынского пограничного отряда.\n\nВ начале Великой Отечественной войны личный состав заставы под его командованием оборонял государственную границу СССР. Первые пять дней заставу безуспешно атаковали стрелковые подразделения. 27 июня была подтянута артиллерия. К 30 июня в живых осталось только 10 человек. 2 июля фашисты сделали подкоп и взорвали подвал.\n\nПограничники 13-й заставы 11 дней героически сражались в полном окружении. Они погибли смертью храбрых, но не сдались.\n\nУказом Президиума Верховного Совета СССР от 18 декабря 1957 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Маковецкий Федор Ефремович",photo:"images/heroes_ussr/makovetsky.jpg",rank:"Герой Советского Союза",bio:"Родился 25 февраля 1899 года в деревне Богдановка Витебской области. В 1938–1941 годах преподавал тактику и топографию в Саратовском военном училище НКВД СССР.\n\nОборонял Сталинград в составе 62-й армии. Командовал учебным батальоном, затем 161-м стрелковым полком. Оборонял Мамаев курган, вёл бои в районе заводов «Баррикады» и «Красный Октябрь». С 6 июля 1943 года участвовал в боях на Курской дуге.\n\nВесной 1945 года, освобождая Чехословакию, был тяжело ранен, ему ампутировали ногу.\n\nУказом Президиума Верховного Совета СССР от 17 октября 1943 года присвоено звание Героя Советского Союза."},
{name:"Малиновский Михаил Елисеевич",photo:"images/heroes_ussr/malinovsky.jpg",rank:"Герой Советского Союза",bio:"Родился 3 октября 1914 года в селе Чернолучье Омской области. В два часа ночи 15 октября 1943 года его взвод начал переправу через Днепр. Вблизи правого берега противник открыл огонь, плот был разбит, однако Малиновский со своими солдатами вплавь добрался до берега. Захватили и расширили плацдарм. За всё время переправы отряд не понёс ни одной потери.\n\nОкончил курсы младших лейтенантов в Саратовском училище войск НКВД.\n\nУказом Президиума Верховного Совета СССР от 30 октября 1943 года присвоено звание Героя Советского Союза."},
{name:"Мамонов Николай Васильевич",photo:"images/heroes_ussr/mamonov.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился 27 сентября 1919 года в деревне Пашенино Вологодской области. С 14 августа 1940 года — курсант Саратовского училища войск НКВД. С июля 1941 года на фронтах войны. С 22 апреля 1943 года — командир 331-го стрелкового полка.\n\nВ ноябре 1943 года полк одним из первых вошёл в Гомель. 12 октября 1944 года полк прорвал оборону противника с плацдарма на реке Нарев. 26 октября 1944 года 25-летний командир полка был смертельно ранен осколком авиационной бомбы.\n\nУказом Президиума Верховного Совета СССР от 24 марта 1945 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Марушин Николай Алексеевич",photo:"images/heroes_ussr/marushin.jpg",rank:"Герой Советского Союза",bio:"Родился 6 октября 1925 года в деревне Ивановка Нижегородской области. Окончил школу снайперов. С апреля 1944 года — на фронтах войны.\n\n5 февраля 1945 года отделение Марушина в числе первых переправилось через Одер в районе города Фюрстенберга и приняло активное участие в боях за взятие этого города. Лично уничтожил вражеский орудийный расчёт.\n\nВ 1963 году окончил Саратовское военное училище МВД СССР.\n\nУказом Президиума Верховного Совета СССР от 24 марта 1945 года присвоено звание Героя Советского Союза."},
{name:"Машинцев Михаил Савельевич",photo:"images/heroes_ussr/mashintsev.jpg",rank:"Герой Советского Союза",bio:"Родился 18 декабря 1909 года в селе Лещиново Пензенской области. В 1936 году окончил Саратовскую военную школу пограничной охраны и войск НКВД СССР.\n\nВ январе 1945 года батальон майора Машинцева прорвал две линии немецкой обороны. 3 февраля 1945 года батальон переправился через Одер и участвовал в боях за плацдарм, отразив пять контратак. В бою Машинцев был три раза ранен, последний — тяжело, но продолжил руководить батальоном.\n\nУказом Президиума Верховного Совета СССР от 6 апреля 1945 года присвоено звание Героя Советского Союза."},
{name:"Немчинов Александр Михайлович",photo:"images/heroes_ussr/nemchinov.jpg",rank:"Герой Советского Союза",bio:"Родился 15 ноября 1919 года в селе Воскресенское в Башкирской АССР. Командир орудия 63-го отдельного истребительно-противотанкового дивизиона. 15 октября 1943 года первым переправил орудие через Днепр в районе посёлка Лоев. Уничтожил орудие, 2 пулемёта и до 25 гитлеровцев.\n\nВ 1949 году окончил Саратовское военное училище войск МГБ СССР.\n\nУказом Президиума Верховного Совета СССР от 30 октября 1943 года присвоено звание Героя Советского Союза."},
{name:"Ракус Дмитрий Иванович",photo:"images/heroes_ussr/rakus.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился в январе 1918 года в селе Ободы Сумской области Украины. По окончании школы поступил в Саратовское военное училище НКВД. В декабре 1939 года был направлен в Ленинградский пограничный округ. Первый бой с финнами принял 3 января 1940 года на реке Уксуниоки.\n\n17 января лейтенант Ракус с группой из десяти красноармейцев обнаружил в лесу окоп с ротой финских солдат. Несмотря на многократное превосходство противника, принял решение уничтожить диверсантов. Подобравшись к позициям, пограничники закидали их гранатами и ворвались в окоп. Около 30 финских солдат и три офицера были уничтожены.\n\n27 января 1940 года на дороге у посёлка Колатсельга его отряд попал в засаду. Дмитрий Иванович поднял пограничников в атаку, но был сражён вражеской пулей.\n\nУказом Президиума Верховного Совета СССР от 26 апреля 1940 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Рубцов Герасим Архипович",photo:"images/heroes_ussr/rubtsov.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился 18 февраля 1904 года в селе Берёзовка Воронежской области. В 1930 году окончил Омскую пехотную школу. С 1935 года — преподаватель тактики в 4-й школе пограничной охраны в г. Саратове.\n\nКомандовал 456-м сводным пограничным полком войск НКВД Приморской армии. Участвовал в обороне Севастополя, в течение 250 дней оборонял важные рубежи, уничтожив около 2 пехотных полков, 11 танков, сбив 2 бомбардировщика. Отказался эвакуироваться на Кавказ. В июле 1942 года погиб в бою.\n\nУказом Президиума Верховного Совета СССР от 8 мая 1965 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Серёжников Александр Иванович",photo:"images/heroes_ussr/serezhnikov.jpg",rank:"Герой Советского Союза (посмертно)",bio:"Родился 15 августа 1915 года на хуторе Грушевка Ростовской области. В 1937 году окончил Саратовское военное училище НКВД. Командир стрелкового полка.\n\n20 сентября 1943 года полк обеспечил форсирование реки Десна. 21 сентября полк ворвался в город Чернигов, форсировал Днепр и закрепился на плацдарме. 2 октября 1943 года погиб в бою.\n\nУказом Президиума Верховного Совета СССР от 16 октября 1943 года присвоено звание Героя Советского Союза (посмертно)."},
{name:"Терёшкин Пётр Федорович",photo:"images/heroes_ussr/tereshkin.jpg",rank:"Герой Советского Союза",bio:"Родился 1 июля 1907 года в посёлке Колышлей Пензенской области. В пограничных войсках ОГПУ СССР с 1929 года. Окончил школу младшего начсостава и 1-ю Кавалерийскую школу ОГПУ. Служил начальником пограничной заставы в Средней Азии. Участник боёв у озера Хасан 29 июля — 11 августа 1938 года. При атаке японскими войсками сопки Заозёрной старший лейтенант Терёшкин грамотно организовал оборону и отбил несколько атак. Получил несколько ранений, но остался в строю.\n\nВ 1941 году окончил Военную академию имени М. В. Фрунзе. Участник Великой Отечественной войны с июня 1941. Попал в окружение и был пленён. Бежав из плена, в мае 1943 года вступил в партизанский полк «13». С 1944 года командовал частями войск НКВД. Работал преподавателем Саратовского военного училища МВД СССР.\n\nУказом Президиума Верховного Совета СССР от 25 октября 1938 года присвоено звание Героя Советского Союза."},
{name:"Федулов Павел Иванович",photo:"images/heroes_ussr/fedulov.jpg",rank:"Герой Советского Союза",bio:"Родился 31 декабря 1918 года в городе Кинешме Ивановской области. Окончил Саратовское военное училище НКВД 28 июня 1941 года. Был направлен на границу с Афганистаном. С первых дней войны писал рапорты об отправке на фронт.\n\n14 января 1945 года рота гвардии капитана Федулова, преодолев минное поле и две линии траншей, атаковала высоту. Капитан обошёл высоту с тыла и уничтожил дзот. Рота с ходу форсировала реку Пилицу, захватила и расширила плацдарм.\n\nОкончил Военную академию имени М. В. Фрунзе. Защитил кандидатскую диссертацию.\n\nУказом Президиума Верховного Совета СССР от 27 февраля 1945 года присвоено звание Героя Советского Союза."},
{name:"Яровой Артемий Сергеевич",photo:"images/heroes_ussr/yarovoy.jpg",rank:"Герой Советского Союза",bio:"Родился 2 ноября 1908 года в селе Петровичи Приморского края. В 1934 году окончил 4-ю школу пограничной охраны войск ОГПУ в г. Саратове. Участник Советско-японской войны 1945 года.\n\nБатальон под командованием капитана Ярового 9 августа 1945 года форсировал реку Амур, освободил китайские города Цике и Сюнхэ. В бою за Мананьтуньский узел сопротивления лично возглавлял атаки. Получив ранение, остался в строю до полного выполнения задачи.\n\nУказом Президиума Верховного Совета СССР от 8 сентября 1945 года присвоено звание Героя Советского Союза."}
];

const HEROES_SOC_LABOR = [
{name:"Витченко Степан Степанович",photo:"images/heroes_soc/vitchenko.jpg",rank:"Герой Социалистического Труда",bio:"Родился в 1909 году в Харьковской губернии. В 1938 году окончил Саратовское военное училище пограничной и внутренней охраны НКВД. Отличился в ходе Финской войны: во главе штурмовой группы захватил заминированный мост через реку.\n\nПосле войны продолжил службу в пограничных войсках. В 1955 году вышел в отставку в звании полковника запаса. Работал слесарем на заводе «Электросила». Создал систему наставничества молодёжных бригад. За 15 лет рабочую школу Витченко прошли более 150 рабочих. Опыт был внедрён на предприятиях СССР, Болгарии, Венгрии и ГДР.\n\nУказом Президиума Верховного Совета СССР от 23 апреля 1974 года присвоено звание Героя Социалистического Труда."},
{name:"Плехов Виктор Владимирович",photo:"images/heroes_soc/plekhov.jpg",rank:"Герой Социалистического Труда",bio:"Родился 1 мая 1927 году в деревне Вятка Омской области. В 1945 году призван в ряды Красной Армии, служил в Кремлёвском полку. Участник Парада Победы 1945 года. Проходил обучение в Саратовском военном училище НКВД СССР.\n\nПосле увольнения в запас устроился на завод технического стекла. Освоил профессию машиниста проката широкогабаритного стекла. Именно он зажёг первый факел в печах 15 марта 1958 года, дав старт новому производству. В 1961 году изготовлено стекло для Дворца съездов в Кремле.\n\nУказом Президиума Верховного Совета СССР от 7 мая 1971 года присвоено звание Героя Социалистического Труда."},
{name:"Хафизов Шариф Сагирович",photo:"images/heroes_soc/khafizov.jpg",rank:"Герой Социалистического Труда",bio:"Родился 25 июня 1920 г. в деревне Щербень Татарской АССР. С октября 1940 года служил в НКВД по охране железнодорожных сооружений. С первого дня войны участвовал в боях. Получил четыре ранения. Участвовал в боях под Москвой, был снайпером на Северо-Западном фронте.\n\nС марта 1943 года — курсант Саратовского военного училища НКВД. После войны работал в органах внутренних дел Татарской АССР. В 1955 году возглавил колхоз «Дружба».\n\nУказом Президиума Верховного Совета СССР от 31 декабря 1965 года за успехи в повышении урожайности и производстве сахарной свёклы присвоено звание Героя Социалистического Труда."}
];

const HEROES_RUSSIA = [
{name:"Белоглазов Александр Михайлович",photo:"images/heroes_russia/beloglazov.jpg",rank:"Герой Российской Федерации",bio:"Родился 29 января 1978 года в селе Большой Карай Романовского района Саратовской области. В 1995 году окончил Большекарайскую среднюю общеобразовательную школу.\n\nС 1995 года — курсант Саратовского высшего военного командного Краснознамённого училища внутренних войск Министерства внутренних дел России им. Ф. Э. Дзержинского (в 1997 году училище преобразовано в институт). Учился во взводе специального назначения, с 3-го курса — командир отделения и старший сержант. В 1997 году проходил войсковую стажировку в учебной роте специального назначения в Отдельной дивизии оперативного назначения (ОДОН) имени Ф. Э. Дзержинского, а в 1999 году — в отряде специального назначения «Витязь», где получил рекомендации командира отряда. В 2000 году с отличием окончил учёбу. В том же году сдал норматив на право ношения крапового берета.\n\nС 2000 года проходил службу в ОДОН. В последующем продолжил службу в 1-м Краснознамённом отряде специального назначения (1-й ОСН) «Витязь». В 2004 году поступил в Общевойсковую академию Вооружённых Сил Российской Федерации. После окончания академии вернулся в ОСН «Витязь», который в 2008 году был преобразован в 604-й Центр специального назначения (ЦСН) внутренних войск МВД России «Витязь».\n\nВ 2021 году назначен командиром 604-го ЦСН «Витязь», который в 2022 году принял активное участие в специальной военной операции по защите Донецкой и Луганской Народных Республик. За первые два месяца спецоперации они сумели овладеть 18 опорными пунктами противника, подавили свыше 50 огневых точек, уничтожили 30 единиц бронетехники. Полковник Белоглазов лично командовал этими операциями.\n\nКогда колонна тактической группы «Витязя» попала в засаду у переправы через реку, полковник Белоглазов спас своих подчинённых. С первой частью колонны он сумел прорваться вперёд, отвёл людей на безопасное расстояние, и сам, сформировав офицерскую группу, вернулся назад под миномётный обстрел. Им удалось разминировать мост и вывести из-под огня всех остальных бойцов.\n\nПод его руководством был захвачен хорошо укреплённый стратегический объект. Бойцы «Витязя» совместно с десантниками сумели выбить их в первые же сутки.\n\nНаграждён орденом Мужества, орденами «За заслуги перед Отечеством» 1-й и 2-й степени, медалями «За отвагу», Суворова.\n\nУказом Президента Российской Федерации от 2022 года за героизм и мужество, проявленные при выполнении специального задания, присвоено звание Героя Российской Федерации с вручением знака особого отличия — медали «Золотая Звезда».\n\nНаграда была вручена 20 мая 2022 г. директором Федеральной службы войск национальной гвардии Российской Федерации — главнокомандующим войсками национальной гвардии Российской Федерации В. В. Золотовым в Отдельной дивизии особого назначения им. Ф. Э. Дзержинского в г. Балашихе (Московская область)."},
{name:"Белозеров Сергей Павлович",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 22 октября 1977 года в городе Харабали Астраханской области в семье врачей. Окончил среднюю школу. В годы учёбы занимался лёгкой атлетикой, настольным теннисом, играл во взрослой футбольной команде.\n\nС 1994 года — в Вооружённых Силах Российской Федерации, курсант Саратовского высшего военного командного Краснознамённого училища внутренних войск имени Ф. Э. Дзержинского Министерства внутренних дел Российской Федерации. С первого курса был сержантом, командиром отделения.\n\nПосле окончания института в 1999 году служил на командных должностях в частях внутренних войск МВД России. Уже через полтора месяца службы в 12-й отдельной бригаде (город Астрахань) отправился в командировку в Чеченскую Республику. В дальнейшем его служба проходила в 22-й отдельной бригаде (город Калач-на-Дону, Ростовская область), 23-м отряде специального назначения «Оберег» (город Челябинск), в ходе неё он не раз выполнял боевые задачи на Северном Кавказе, за что был награждён боевыми медалями.\n\nОкончил Общевойсковую военную академию Вооружённых Сил Российской Федерации в Москве.\n\nВ 2011 году подполковник С. П. Белозёров стал командиром 28-го отряда специального назначения «Ратник» Внутренних войск МВД России (с 2016 года — войск национальной гвардии Российской Федерации), который возглавлял более 7 лет. Затем служил начальником штаба 33-й бригады особого назначения Северо-Западного округа, начальником оперативного управления — заместителем начальника штаба Восточного округа войск Росгвардии.\n\nС 24 февраля 2022 года принимал участие в специальной военной операции по защите Донецкой и Луганской Народных Республик, в ходе которой, проявляя героизм, успешно выполнял поставленные перед ним и его подчинёнными задачи.\n\nНаграждён медалью ордена «За заслуги перед Отечеством» с изображением мечей 2-й степени, медалями Суворова, Жукова.\n\nУказом Президента Российской Федерации от 23 ноября 2022 года за мужество и героизм, проявленные при исполнении воинского долга, присвоено звание Героя Российской Федерации с вручением знака особого отличия — медали «Золотая Звезда».\n\nНаграда вручена Герою 8 декабря 2022 года в Георгиевском зале Кремля Президентом России В. В. Путиным."},
{name:"Китанин Роман Александрович",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 1 января 1978 года в рабочем посёлке Тамала Пензенской области. В 1995 году окончил Тамалинскую среднюю школу № 1 с серебряной медалью.\n\nВ Вооруженных Силах Российской Федерации с 1995 года. Окончил с отличием Саратовский военный институт внутренних войск МВД России. Был направлен для дальнейшего прохождения службы в Северо-Кавказский округ внутренних войск МВД России.\n\nВ 2007 году начальник разведки 102-й отдельной бригады внутренних войск майор Роман Александрович Китанин выполнял служебно-боевые задачи в Северо-Кавказском регионе.\n\n2 июня 2007 года разведывательная группа, которую возглавлял майор Китанин, вышла на оперативно-розыскные мероприятия в районе населённого пункта Солнечное Хасавюртовского района Республики Дагестан. При зачистке лесного массива группа попала в засаду боевиков. В ходе боя, двигаясь направляющим в группе, Роман Китанин принял огонь на себя и дал возможность остальным военнослужащим занять боевые позиции. Ценой собственной жизни он спас своих подчинённых. На месте боя было найдено 3 тела убитых боевиков, но судя по крови и следам волочения, их было уничтожено больше. Все они входили в бандгруппу некоего Башаева, совершившего ряд дерзких нападений на сотрудников правоохранительных органов и военнослужащих. В этом бою 2 человека были убиты и 1 ранен.\n\n10 ноября 2007 года в городе Пензе в Областном драматическом театре на торжественном мероприятии, посвящённом Дню милиции, состоялась передача звезды Героя России родственникам Романа Александровича Китанина. Награду передал лично заместитель министра внутренних дел Российской Федерации — главнокомандующий внутренними войсками МВД России генерал армии Николай Евгеньевич Рогожкин.\n\nПриказом Федеральной службы войск национальной гвардии Российской Федерации от 7 сентября 2017 года № 375 майор Роман Александрович Китанин навечно зачислен в списки 9 роты 5 батальона курсантов Саратовского военного ордена Жукова Краснознаменного института войск национальной гвардии Российской Федерации.\n\nУказом Президента Российской Федерации № 1034 от 7 августа 2007 года за мужество и героизм, проявленные при исполнении воинского долга в Северо-Кавказском регионе России, присвоено звание Героя Российской Федерации (посмертно)."},
{name:"Ковалев Александр Геннадьевич",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 15 октября 1973 года в станице Красноармейская (с 1994 года — Полтавская) Красноармейского района Краснодарского края. После окончания школы в 1991 году поступил в Саратовское высшее военное командное училище внутренних войск МВД России, которое закончил в 1996 году. Служил командиром взвода, заместителем командира роты. С 1998 года — заместитель командира группы Армавирского отряда спецназа внутренних войск МВД России.\n\n7 сентября 1999 года с отрядом убыл в командировку в Дагестан. Погиб 10 сентября 1999 года под Новолакском в Дагестане. В бою на высоте 315,3 старший лейтенант Александр Геннадьевич Ковалёв прикрывал отход подчиненных, отстреливался до последнего патрона. Израсходовав боеприпасы, подпустил бандитов к себе и подорвал их и себя гранатой.\n\nПриказом министра внутренних дел Российской Федерации навечно зачислен в списки личного состава части. В станице Полтавской Красноармейского района открыт бюст Героя в 2018 году.\n\nУказом Президента Российской Федерации от 30 декабря 1999 года присвоено звание Героя Российской Федерации (посмертно)."},
{name:"Никишин Александр Николаевич",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 8 марта 1958 года в селе Илек Оренбургской области в семье военнослужащего. Русский. Вскоре семья переехала в город Оренбург, где Александр Николаевич Никишин окончил среднюю школу.\n\nВо внутренних войсках МВД СССР с 1975 года. В 1979 году окончил Саратовское высшее военное командное училище внутренних войск МВД СССР. Служил в Москве в Отдельной мотострелковой дивизии особого назначения имени Ф. Э. Дзержинского внутренних войск МВД СССР. Командовал учебным взводом, ротой и батальоном в войсковой части № 3419. В 1992 году окончил Военную Академию имени М. В. Фрунзе. По её окончании был направлен в отряд специального назначения внутренних войск МВД «Витязь» на должность заместителя командира. В мае-июле 1993 года в составе своего подразделения выполнял задачи по блокированию осетино-ингушской границы. 3 октября 1993 года, во время октябрьских событий в Москве, принимал участие в столкновениях на территории телецентра «Останкино». В апреле 1994 года назначен командиром отряда, исполнял обязанности до июля 1996 года. Принимал непосредственное участие в боевых действиях во время первой чеченской войны.\n\nВ январе 1996 года возглавил большую группу личного состава «Витязя», переброшенную в район села Первомайское, где была заблокирована банда С. Радуева после неудачного бандитского налёта на город Кизляр. В село прорвалось несколько штурмовых групп отряда, одну из которых возглавил лично командир. Было уничтожено боевое охранение противника, спасено и выведено из села несколько десятков заложников из числа мирных жителей. Командование было обеспечено разведданными о численности и обороне противника, бандитам нанесены значительные потери в живой силе.\n\nНаграждён орденом Мужества, орденом «За личное мужество».\n\nУказом Президента Российской Федерации № 689 от 12 мая 1996 года за мужество и героизм, проявленные при выполнении специального задания, присвоено звание Героя Российской Федерации с вручением медали «Золотая Звезда»."},
{name:"Палазник Никита Андреевич",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 15 октября 1995 года в городе Саратове в многодетной семье военнослужащего. Окончил среднюю общеобразовательную школу в 2012 году. С 2008 года активно занимался академической греблей: с 2009 года входил в юношескую сборную Саратовской области, с 2011 года — кандидат в спортивную сборную России. Был победителем областных и всероссийских соревнований, в 2012 году стал серебряным призёром первенства страны.\n\nС 2012 года — курсант Саратовского военного института внутренних войск МВД России. Окончил институт в 2017 году, как лучший выпускник присутствовал на приёме у Президента Российской Федерации.\n\nС 2017 года служил в одном из подразделений Федеральной службы войск национальной гвардии Российской Федерации, которое в 2018 году вошло в состав вновь сформированного 607-го центра специального назначения Северо-Кавказского округа Росгвардии (пункт дислокации — город-курорт Железноводск, Ставропольский край). Прошёл путь до командира группы спецназа. Участник военной операции в Сирии, которую Россия с 2015 года проводит против международных террористических формирований. За боевые отличия награждён медалью Суворова.\n\nС 24 февраля 2022 года в составе своего подразделения принимал участие в специальной военной операции (СВО) по защите Донецкой и Луганской Народных Республик. Неоднократно проявлял доблесть и самоотверженность, за что дважды награждён орденами Мужества.\n\nВ зоне проведения СВО на территории ДНР капитан Палазник с риском для жизни передал старшему начальнику важные разведданные. Это позволило вовремя подготовиться к попытке Вооружённых сил Украины совершить прорыв через российские боевые порядки. В результате атака противника была пресечена с большим уроном для него.\n\nНаграждён орденом Мужества, медалью Суворова.\n\nУказом Президента Российской Федерации от 2023 года за мужество и героизм, проявленные при исполнении воинского долга присвоено звание Героя Российской Федерации с вручением знака особого отличия — медали «Золотая Звезда».\n\nНаграда была вручена 27 марта 2023 года в Зале Славы Музея Победы директором Федеральной службы войск национальной гвардии Российской Федерации — главнокомандующим войсками национальной гвардии Российской Федерации В. В. Золотовым."},
{name:"Паньков Михаил Анатольевич",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 20 июля 1952 года в Бичурском районе Бурятии.\n\nС 1969 года Паньков служил во внутренних войсках МВД СССР.\n\nВ 1973 году закончил Саратовское высшее военное училище внутренних войск МВД СССР, после чего работал на должностях командира взвода, роты, батальона полка и дивизии внутренних войск. Закончил Военную академию имени М. В. Фрунзе, а затем — Военную академию Генерального штаба Вооруженных Сил Российской Федерации.\n\nС 1995 года работал первым заместителем начальника Главного штаба внутренних войск МВД России. Одновременно с 1995 по 1996 годы был командующим группировки внутренних войск в составе группы федеральных войск в Чечне. Принимал участие в первой чеченской войне.\n\nС 1998 года работал на должности заместителя главнокомандующего внутренними войсками МВД России по чрезвычайным ситуациям, а с мая 1999 года — на должности первого заместителя главнокомандующего внутренними войсками МВД России.\n\nС вторжением боевиков в Дагестан в августе 1999 года Михаил Анатольевич Паньков был назначен на должность командующего группировки внутренних войск на Северном Кавказе, на которой проработал до марта 2000 года. Паньков руководил операциями войск, в том числе в Новолакском районе Дагестана, где войска под руководством Панькова освободили 14 сёл, уничтожили 337 боевиков, захватили в плен 48 боевиков. Были захвачены 14 миномётов, 8 зенитных установок, 4 склада боеприпасов и ещё 2 склада были уничтожены.\n\nС октября 1999 года — на территории Чечни, к концу года внутренние войска заняли в Чечне 80 сёл и провели 136 спецопераций. В бою за село Знаменское 14 октября 1999 года командный пункт был атакован боевиками и был окружён. Михаил Анатольевич Паньков руководил отражением атаки. В декабре 1999 — январе 2000 годов принимал участие в штурме Грозного.\n\nВ феврале 2000 года Михаилу Анатольевичу Панькову присвоено воинское звание «генерал-полковник».\n\nС октября 2000 года работал на должности начальника Главного штаба — первого заместителя главнокомандующего внутренними войсками МВД России, с апреля 2002 года — на должности заместителя министра внутренних дел Российской Федерации по Южному Федеральному округу, а с 2005 года — на должности начальника Главного управления МВД России по Южному Федеральному округу.\n\nУказом исполняющего обязанности Президента Российской Федерации № 25 от 11 января 2000 года за проявленное мужество в боях и умелое руководство войсками в борьбе с террористическими формированиями на Северном Кавказе присвоено звание Героя Российской Федерации с вручением медали «Золотая Звезда»."},
{name:"Романов Анатолий Александрович",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 27 сентября 1948 года в с. Михайловка Башкирской АССР. По окончании средней школы работал фрезеровщиком. Осенью 1967 года был призван на военную службу во внутренние войска МВД СССР. В 1972 году окончил Саратовское военное училище МВД СССР имени Ф. Э. Дзержинского. В 1982 году с отличием окончил Военную академию имени М. В. Фрунзе.\n\nС октября 1984 года Анатолий Александрович продолжал службу в спецчастях внутренних войск в должностях: начальника штаба, командира части, заместителя командира соединения.\n\nПосле окончания в 1991 году Военной академии Генерального штаба Вооруженных Сил Российской Федерации командовал соединением, возглавлял спецчасти внутренних войск по охране важных государственных объектов и специальных грузов. С июля 1993 года — заместитель командующего внутренними войсками — начальник управления боевой подготовки ГУКВВ.\n\nВ 1995 году он стал командующим внутренними войсками МВД России и был назначен командующим объединённой группировкой федеральных войск на территории Чеченской Республики. Генерал-полковник Анатолий Романов отвечал за разработку и реализацию так называемого военного блока вопросов при переговорах с лидерами незаконных вооружённых формирований. В сферу его забот входили самые острые проблемы, рождённые вооружённым противостоянием: соблюдение режима прекращения огня, разоружение боевиков и приём оружия от населения, ликвидация автономных и никому не подчинявшихся бандгрупп, установление местных органов власти во множестве населённых пунктов.\n\n6 октября 1995 года были назначены переговоры с одним из лидеров сепаратистов Асланом Масхадовым. В этот же день за несколько часов до переговоров генерал-полковник Анатолий Александрович Романов выехал в аэропорт Северный для встречи с Русланом Хасбулатовым — видным политическим деятелем чеченского происхождения, не единожды предлагавшим свою кандидатуру в роли посредника для урегулирования конфликта, чтобы обсудить некоторые из вопросов для переговоров. В Грозном в тоннеле под железнодорожным мостом на площади Минутка во время следования колонны взорвался радиоуправляемый фугас. УАЗ генерала Романова оказался в центре взрыва. Анатолий Романов был тяжело ранен и впал в кому. Он до сих пор, несмотря на усилия врачей, находится в тяжелом состоянии.\n\nНагражден орденом Красной Звезды, орденом «За личное мужество», орденом «За военные заслуги», пятью медалями. Почетный гражданин г. Саратова.\n\nУказом Президента Российской Федерации № 1075 от 5 ноября 1995 года за мужество и героизм, проявленные при выполнении специального задания, присвоено звание Героя Российской Федерации."},
{name:"Филоненко Андрей Михайлович",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 30 декабря 1989 года в городе Калининске. Окончил среднюю школу №1.\n\nС 2007 года — курсант Саратовского военного института внутренних фойск МВД РФ. Окончил институт в 2012 году.\n\nС 2012 года служил 26 отряде специального назначения войск национальной гвардии Российской Федерации «Барс» (пункт дислокации — город Казань).\n\nС 24 февраля 2024 года в составе своего подразделения принимал участие в специальной военной операции (СВО) по защите Донецкой и Луганской Народных Республик. Неоднократно проявлял доблесть и самоотверженность, за что награжден дважды орденами мужества, медалью за отвагу.\n\n5 января 2025 года Андрей Филоненко вместе с товарищем участвовали в остановке прорыва ВСУ на территорию Курской области. Именно расчёты бойцов Росгвардии сумели вывести из строя первый вражеский танк, что сыграло решающую роль в дальнейшем развитии боя и разгроме противника.\n\nНагражден орденом мужества, медалью за отвагу.\n\nУказом Президента Российской Федерации от 2025 за мужество и героизм, проявленные при выполнении служебно-боевых задач специальной военной операции и за оборону Курской области в первые дни попытки вторжения украинских боевиков года присвоено Звание Героя Российской Федерации с вручением знака особого отличия — медали «Золотая Звезда».\n\nНаграда была вручена 23 февраля 2025 года в Георгиевском зале Большого Кремлевского дворца Президентом России В. В. Путиным."},
{name:"Шевелев Николай Николаевич",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 29 июля 1965 года в селе Еленовское Красногвардейского района Краснодарского края. В 1983 году окончил среднюю школу в родном селе и поступил в Киевский инженерно-строительный институт. В декабре 1983 года призван на срочную службу во внутренние войска МВД СССР. В 1984 году из войск поступил в Саратовское высшее военное командное училище МВД СССР имени Ф. Э. Дзержинского, которое окончил с отличием в 1988 году.\n\nДля прохождения службы был направлен в Уральский округ внутренних войск, где последовательно прошёл должности командира взвода, заместителя командира и командира роты, заместителя командира батальона, с 1995 года — начальника группы боевой подготовки полка. Служил в воинской части в городе Свердловске. В 1998 году окончил Военную академию имени М. В. Фрунзе. С этого года служил в 451-м полку оперативного назначения Северо-Кавказского округа внутренних войск старшим помощником начальника штаба полка, командиром батальона. Участник боевых действий второй чеченской войны, совершил три командировки в Дагестан и в Чечню.\n\nВ апреле 2000 года в третий раз прибыл в Чечню. В середине апреля 2000 года в районе входа в Веденское ущелье участились обстрелы блокпостов внутренних войск. 23 апреля под Сержень-Юртом в Аргунском ущелье боевики разгромили тыловую колонну десантников. Именно туда на БТР и БМП направилась поисково-разведывательная группа, которой руководил подполковник Николай Николаевич Шевелёв. 26 апреля разведчики обнаружили отряд боевиков в количестве до 60 человек. Подполковник Николай Николаевич Шевелёв принял решение начать боевые действия, запросив предварительно по рации подкрепление. Однако в тылу российского отряда оказалась ещё одна группа чеченских боевиков, и до прибытия подкрепления пришлось вести огонь на «два фронта». После гибели комбата командование на себя взял лейтенант Калин. К вечеру того же дня боевики были разбиты. Потери среди российских военнослужащих составили 10 человек. Боевики потеряли, как минимум, 25 человек.\n\nУказом Президента Российской Федерации № 64 от 29 января 1997 года за мужество и героизм, проявленные при выполнении воинского долга, присвоено звание Героя Российской Федерации."},
{name:"Яфаров Джафяс Джафарович",photo:"images/hero_russia.png",rank:"Герой Российской Федерации",bio:"Родился 28 ноября 1976 года в селе Татарский Канадей Пензенской области. Окончил среднюю школу.\n\nВ 1994 году поступил на службу во внутренние войска МВД России. С 1999 года по окончании Саратовского военного института внутренних войск МВД России служил в отряде специального назначения «Росич» внутренних войск МВД России.\n\nУчаствовал в боевых действиях во время второй чеченской войны. В начале марта 2000 года в составе отряда штурмовал село Комсомольское, где были блокированы свыше 1000 боевиков Руслана Гелаева. Группа лейтенанта Яфарова, захватив укреплённый дом на перекрёстке улиц, обеспечила продвижение российских частей в село, но оказалась отрезанной огнём боевиков от основных сил. Лейтенант Джафяс Джафарович Яфаров лично уничтожил несколько моджахедов, вынес из-под огня раненого гранатомётчика, был ранен, контужен, но остался в строю. При прорыве к своим 6 марта 2000 года был убит выстрелом снайпера в голову.\n\nУказом Президента Российской Федерации № 1267 от 7 июля 2000 года за мужество и героизм, проявленные в ходе контртеррористической операции на Северном Кавказе, присвоено звание Героя Российской Федерации (посмертно)."}
];

const POSTWAR_PAGES = [
{photo:"images/photo21.png",title:"Период 1945–1953",bio:"Период истории училища с 1945 по 1991 годы едва ли не самый сложный в плане исследования. В это время более десяти раз проводилась реорганизация структуры, изменения штатов, открывались и закрывались отделения, вводились новые специальности.\n\nПосле преобразований в войсках правопорядка штатные преобразования произошли и в Саратовском военном училище. С 1946 года училище начинает именоваться Саратовским военным училищем МВД СССР. Учебные отделы пехотного и медицинского отделений были объединены в общий учебный отдел. Батальоны переименованы в дивизионы.\n\nВ 1946 году создаются три новых отделения: политическое, интендантское и радиоспециальной связи, а также введены курсы переподготовки старшего политсостава войск.\n\nВ марте 1947 года Саратовское военное училище передавалось в ведение Министерства госбезопасности. Перед училищем была поставлена задача готовить офицеров, способных умело организовать и руководить стрелковым взводом и ротой в условиях современного боя."},
{photo:"images/photo22.png",title:"Реорганизация (1953–1960-е)",bio:"5 марта 1953 г. было принято решение об объединении МВД и МГБ в одно министерство — МВД СССР. 2 мая 1953 года училище отмечало свой 20-летний юбилей. В приветствии командования войск подчёркивалось, что праздник училища — это праздник всех войск МВД.\n\nС 1 октября 1953 года училище стало именоваться Саратовским военным училищем МВД СССР. Начинается подготовка офицеров — организаторов службы по охране исправительно-трудовых учреждений и особо важных объектов промышленности.\n\nВ связи с 25-летием училища в 1957 году оно было награждено Почётной грамотой Президиума Верховного Совета РСФСР."},
{photo:"images/photo23.png",title:"60-е годы. Связь с общественностью",bio:"Шестидесятые годы явились новой яркой страницей связи училища с общественностью города Саратова и области, с трудовыми коллективами, молодёжными организациями, студентами и школьниками.\n\nКурсанты и офицеры активно участвовали в военно-патриотическом воспитании подрастающего поколения и охране общественного порядка в городе.\n\nЗа хорошую организацию и высокие показатели в военно-патриотической работе комсомольская организация училища была награждена Почётной Грамотой ЦК ВЛКСМ."},
{photo:"images/photo24.png",title:"Присвоение имени Ф. Э. Дзержинского",bio:"30 августа 1966 года постановлением Совета Министров РСФСР № 649 Саратовскому военному училищу было присвоено имя Ф. Э. Дзержинского.\n\nПо поручению командования войск группа военнослужащих во главе с генерал-майором Е. И. Беловым выезжала на встречу с супругой Ф. Э. Дзержинского Софьей Зигмундовной. В ходе встречи она сделала дарственную надпись-пожелание на книге курсантам училища."},
{photo:"images/photo25.png",title:"Статус высшего училища. Орден Красного Знамени",bio:"24 мая 1973 г. военным училищам присваивался статус высших. Саратовское высшее военное училище перешло на программу высших военных учебных заведений. Срок обучения установлен в четыре года. В 1977 году произведён первый выпуск по программе высшего военного училища.\n\n19 мая 1982 года за заслуги в подготовке квалифицированных кадров и в ознаменование 50-летия училище было награждено орденом Красного Знамени. Вручение ордена состоялось 6 июня 1982 года на площади Революции. Орден вручил начальник внутренних войск МВД СССР генерал армии И. К. Яковлев."},
{photo:"images/photo26.png",title:"XXII Олимпийские игры 1980 г.",bio:"Крупнейшим событием стали XXII Олимпийские игры 1980 г. в Москве. Саратовское военное училище выделяло полк в количестве 1050 человек. Перед училищем стояла задача: не выдавая принадлежности к правоохранительным органам, в гражданской одежде, осуществлять охрану спортсменов в Олимпийской деревне.\n\nЛичный состав успешно справился с задачами. За весь период не было ни одного случая нарушения дисциплины. Было предотвращено более 120 нарушений порядка. Двадцать два офицера и два курсанта награждены орденами и медалями Советского Союза."},
{photo:"images/photo27.png",title:"Война в Афганистане",bio:"Не обошла стороной Саратовское военное училище и война в Афганистане. Уже в январе 1980 года по приказу Министра внутренних дел в городе Ташкенте были созданы курсы по подготовке командиров для войск Цорандоя из числа афганцев. В их профессиональном становлении самое активное участие приняли офицеры военного института.\n\nУчастники войны в Афганистане: полковники Н. В. Володин, Н. М. Костечко, Ю. Е. Горбунов, П. А. Даниленко, А. П. Селезнёв, П. В. Грачёв, С. В. Шувалов, А. Н. Полтарецкий и другие — продолжали вносить весомый вклад в подготовку высококвалифицированных кадров для внутренних войск."}
];

const WAR_PAGES = [
{photo:"images/фото_годыВОВ/фото/Рисунок15.png",title:"Начало Великой Отечественной войны",bio:"День начала Великой Отечественной войны — 22 июня 1941 года — училище встретило, находясь в летнем лагере «Разбойщина». Немедленно, после выступления по радио В. М. Молотова, в училище был организован митинг. Переменный и постоянный состав был призван к напряженной работе и бдительности. Объекты училища были взяты под усиленную охрану. Согласно мобилизационному плану, была введена высшая степень боевой готовности.\n\nИзвестие о вероломном нападении фашистской Германии вызвало у личного состава высочайший патриотический подъем. На имя командования поступили многочисленные заявления об отправке на фронт."},
{photo:"images/фото_годыВОВ/фото/Рисунок16.png",title:"Досрочный выпуск офицеров",bio:"24 июня 1941 года, на третий день войны, состоялся досрочный выпуск курсантов второго курса. Выпускную комиссию возглавил начальник училища полковник А. В. Воробейков. 28 июня 1941 года был проведен досрочный выпуск курсантов первого курса.\n\nВсего за первую неделю войны из Саратовского военного училища в войска убыл 801 молодой офицер. Из них были членами ВКП(б) — 31 человек, кандидатами в члены партии — 87, комсомольцами — 561 и беспартийными лишь 22 лейтенанта."},
{photo:"images/фото_годыВОВ/фото/Рисунок17.png",title:"На передовой. Подвиг пограничников",bio:"К началу войны многие из выпускников командовали заставами или были работниками штабов. Они первыми приняли на себя удар фашистских захватчиков. Из 485 пограничных застав, подвергшихся нападению в первые дни войны, не было такой, которая сдалась бы врагу или оставила охраняемый участок без приказа. В большинстве случаев гарнизоны гибли до последнего человека.\n\nВыпускник училища 1934 года Г. С. Полевода является героем первого контрудара Советских войск в Великой Отечественной войне. В ночь на 23 июня 1941 года его отряд с ходу атаковал врага. Удар был таким сильным и внезапным, что противник не успел оказать серьезного сопротивления."},
{photo:"images/фото_годыВОВ/фото/Рисунок18.png",title:"Подвиг старшего лейтенанта Полеводы",bio:"Командир сводного батальона старший лейтенант Г. С. Полевода был в первых рядах наступающих, личным примером вдохновляя бойцов и командиров. 29 и 30 июня 1941 года его батальон отбил несколько яростных атак гитлеровцев.\n\nВ одном из боев отважный комбат Г. С. Полевода погиб. Указом Президиума Верховного Совета СССР от 27 мая 1967 года старший лейтенант Григорий Степанович Полевода посмертно награжден орденом Отечественной войны I степени."},
{photo:"images/фото_годыВОВ/фото/Рисунок 19.png",title:"13-я пограничная застава лейтенанта Лопатина",bio:"Выпускник Саратовского военного училища НКВД 1940 года — командир 13-й пограничной заставы 90-го Владимир-Волынского пограничного отряда лейтенант Алексей Лопатин. На заставе было 57 бойцов и офицеров. Против них наступала 11-я танковая дивизия и пехотные подразделения гитлеровцев.\n\nПервые пять дней заставу безуспешно атаковали. 27 июня была подтянута артиллерия. К 30 июня в живых осталось только 10 человек. 2 июля фашисты сделали подкоп и взорвали подвал. Пограничники 13-й заставы 11 дней героически сражались в полном окружении. Они погибли смертью храбрых, но не сдались.\n\nВ 1957 году лейтенанту Лопатину посмертно присвоено звание Героя Советского Союза."},
{photo:"images/фото_годыВОВ/фото/Рисунок 20.jpg",title:"Итоги войны. День Победы",bio:"Всего за годы Великой Отечественной войны училище подготовило: офицеров-пехотинцев — 5066, офицеров-саперов — 100, офицеров-химиков — 101, политработников — 299, медиков — 316, химинструкторов — 93, радиооператоров — 188. Всего — 6136 специалистов.\n\nОколо половины из них были направлены в действующую армию. Выпускники защищали Брестскую крепость, обороняли Москву и Ленинград, Киев и Одессу, сражались на Курской дуге. Более 3000 награждены правительственными наградами, а 24 удостоены звания Героя Советского Союза.\n\n9 мая 1945 года с ликованием встретили курсанты и офицеры День Победы. В 1945 году от имени Советского Правительства сотрудникам училища было вручено 1296 наград."}
];

const CREATION_PAGES = [
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок1.png",title:"Саратовский военный институт",bio:"С первого дня образования пограничной школы и по сегодняшний день военный институт готовит высококвалифицированных офицеров для подразделений правопорядка. За период своего существования Саратовский военный институт подготовил более 40 тысяч офицеров. В годы Великой Отечественной войны 24 выпускникам было присвоено звание Героя Советского Союза. Офицеры и курсанты Саратовского училища в послевоенные годы неоднократно принимали участие в войсковых операциях по борьбе с националистическими формированиями в Западной Украине, в Прибалтике и на Северном Кавказе. Выпускники и преподаватели нашего военного училища участвовали в выполнении интернационального долга в Республике Афганистан.\n\nСаратовский военный институт на протяжении всей своей истории сохраняет и приумножает лучшие традиции российского военного образования. В настоящее время в военном институте сформирован высокопрофессиональный профессорско-преподавательский коллектив, передающий свой богатый опыт и передовые знания будущим офицерам войск национальной гвардии. Неоценимый вклад в формирование будущих офицеров вносят ветераны института.\n\nЕсли вы пройдетесь по Саратову по улице Московской вниз от железнодорожного вокзала, то ваш взгляд невольно притянется к памятнику двум красноармейцам за чугунной оградой у фасада центрального здания старейшего военного вуза России.\n\nС 1932 года здесь размещается Саратовский военный ордена Жукова Краснознаменный институт войск национальной гвардии Российской Федерации – кузница офицерских кадров для войск национальной гвардии. За время своего существования институт дал путевку в жизнь не одному поколению офицеров. С 1932 по 2026 год было проведено 100 выпусков основного курса и 37 экстерном, более 40 тысяч воспитанников получили первое офицерское звание «лейтенант»."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок2.png",title:"Награды военного института",bio:"На начальных этапах развития наиболее эффективной считалась деятельность 4-й школы в Саратове, что обуславливает стабильность ее функционирования во все последующие годы. Со временем она стала военным училищем, затем высшим военным командным Краснознаменным училищем МВД, впоследствии получила статус  военного института внутренних войск МВД России, а с 2016 года, с момента образования Федеральной службы войск национальной гвардии, является военной образовательной организацией высшего образования войск национальной гвардии.\n\nУказом Президиума Верховного Совета СССР от 6 мая 1982 года за заслуги в подготовке квалифицированных кадров для внутренних войск училище награждено орденом Красного Знамени\n\nУказом Президента Российской Федерации от 22 марта 2017 года военный институт награжден орденом Жукова."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок3.png",title:"Выпускники и генералы",bio:"Выпускники военного института первыми встречали фашистских захватчиков на границе, активно участвовали в боевых действиях, защищали Брестскую крепость, обороняли Москву и Ленинград, Киев и Одессу, Ростов и Сталинград, сражались на Северном Кавказе и Курской дуге. Более 5 тысяч выпускников военного института за проявленное мужество, отвагу и умелое командование подразделениями в боях с немецко-фашистскими захватчиками и бандами националистов награждены орденами и медалями, а двадцати четырем выпускникам присвоено звание Героя Советского Союза.\n\nБолее 180 выпускников военного института стали генералами. Среди них Герой России, бывший командующий внутренними войсками, генерал-полковник Анатолий Романов, прошедший в стенах училища путь от курсанта до подполковника, командира батальона.\n\nВ 1995, 1996, 2018 и 2019 годах парадные расчеты военного института принимали участие в парадах Победы на Красной площади в г. Москве.\n\nСаратовский военный ордена Жукова Краснознаменный институт войск национальной гвардии Российской Федерации прошел знаменательный путь, внес достойный вклад в дело строительства современного общества в стране, в защиту рубежей нашей Родины и мирного труда сограждан.\n\nДесятки тысяч офицеров получили в военном институте военное и специальное образование, воспитание и необходимую практическую подготовку для ратного труда, выполнения ответственных задач боевой службы и защиты Отечества. Военный институт из года в год готовит высококвалифицированные офицерские кадры, в обучении которых задействован значительный профессорско-преподавательский состав. На 14 кафедрах военного института трудятся 13 докторов наук, 71 кандидат наук, 52 доцента, 18 преподавателей имеют ученое звание «профессор». Кроме штатных сотрудников к обучению курсантов привлекаются до 30 докторов и кандидатов наук других образовательных учреждений города Саратова."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок4.png",title:"Создание системы подготовки кадров",bio:"К 1930 году назрела острая необходимость в создании собственной школьно-курсовой сети для подготовки и переподготовки среднего начсостава войск ОГПУ.\n\nГлавным звеном в подготовке начсостава являлись военно-учебные заведения. Поэтому, прежде всего, были приняты меры к расширению сети военных академий, училищ, школ, различных курсов и увеличению их пропускной способности.\n\nБольшого напряжения потребовала перестройка системы обучения среднего командного состава. Основные усилия здесь были сосредоточены на формировании новых военных школ, расширении емкости и увеличении пропускной способности имевшихся школ, особое внимание уделялось подготовке военно-технических кадров."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок5.png",title:"Формирование 4-й школы",bio:"В первые годы советской власти отдельной системы подготовки кадров среднего командного состава для войск внутреннего предназначения не существовало. Пополнение войск ВЧК – ВОХР – ВНУС – ОГПУ командирами, политработниками и различными специалистами осуществлялось на общих с Красной Армией основаниях. Руководство ОГПУ, по согласованию с высшими государственными органами, направляло по разнарядкам военнослужащих своего ведомства на обучение в учебные заведения РККА, так называемые «нормальные» военные школы, дававшие базовое военное образование в течение двух-трех лет. В погранохрану и войска ОГПУ направлялось около 1/3 выпускников этих школ.\n\nНачиная с 1930 г. коллегия ОГПУ принимает меры к практическому осуществлению намеченной программы в области подготовки кадров. 14 мая 1930 г. в Ленинграде начала работать Ленинградская бронетанковая школа погранохраны и войск ОГПУ, готовившая кадры специалистов для мотомеханизированных подразделений войск. 14 ноября 1930 г. была открыта 1-я школа погранохраны и войск ОГПУ (Новый Петергоф). В ходе реализации кадровой программы руководство ОГПУ пришло к выводу, что выпускников этих школ не хватит для коренного улучшения количественных и качественных характеристик начальствующего состава погранохраны и войск ОГПУ. С учетом опыта формирования 1-й школы и с привлечением части ее командно-преподавательского состава, 26 декабря 1931 г. создана 2-я школа (Харьков), 4 февраля 1932 г. – 3-я школа (Бабушкин), 19 мая 1932 г. – 4-я школа (Саратов).\n\nДля формирования 4-й школы начальствующего состава пограничной охраны и войск ОГПУ выделялось несколько отдельно расположенных зданий, высвободившихся после перемещения административного центра Нижневолжского края из Саратова в Сталинград. Все эти здания были мало приспособлены для размещения военно-учебного заведения. В связи с этим на договорных началах с Наркомпросом был произведен обмен указанных зданий на строящиеся на Московской площади корпуса химического факультета Саратовского государственного университета имени Н. Г. Чернышевского. Сегодня трудно установить, в каких зданиях предполагалось разместить 4-ю школу, но можно с большой долей вероятности предположить, что это были здания бывших Городских казарм, обозначенных на плане города Саратова 1912 г. под номером 37. Старые казармы губернского батальона были возведены в 1850. Неподалеку расположены Новые казармы военного гарнизона, которые построили в 1898 году. Теперь в Новых казармах находится корпус № 6 Саратовского государственного университета имени Н. Г. Чернышевского."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок6.png",title:"Строительство зданий школы",bio:"На этой базе 15 июня  1932 г. началось строительство основных зданий школы, то есть трех корпусов основного здания и вспомогательных помещений в форме цифры «4» и буквы «Ш».\n\nЮридически деятельность 4-й школы начинается 18 августа 1932 года.  В этот день, еще до прибытия в Саратов начальника – военкома школы Абрамовича Сергея Ивановича, его заместитель С. К. Апанасевич издал приказ  № 1, в котором говорилось: «Впредь до утверждения штата вв/мне школы, с сего числа приступить к организационному оформлению Штаба Школы по проекту штата. На организационное скалачивание аппарата управления штаба обратить пребывающий начальстующий состав из ОК ОГПУ, с частичным изпользованием личного состава ремонтно-строительной конторы школы. Техническому руководителю тов. ДЕМИНУ требуемое количество сотрудников из личного состава Ремстройконторы передать для временного замещения должностей в аппарат части материального обеспечения Школы.\n\n19 августа 1932 года приказом № 2 по школе был объявлен временный список аппарата Управления Штаба школы. В него вошли сотрудники, прибывшие по направлению отдела кадров ОГПУ и отдельные специалисты ремонтной строительной конторы. Структурно аппарат управления включал в себя: штаб, строевое отделение, учебную часть, часть материального обеспечения и комендатуру."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок7.png",title:"Руководство строительством",bio:"С этого времени начальник-военком школы С. И. Абрамович берет на себя все руководство строительством и вводит жесткий порядок внутренней жизни школы.\n\nПод личный контроль начальника школы был взят учет поступавших материалов и их расход. Надзор за качеством производимых строительных работ осуществлялся технической комиссией. Одновременно был произведен учет объектов охраны строительства и складских помещений, установлено количество ночных, дневных и суточных постов охраны, проверено противопожарное состояние и наличие пожарного инвентаря. Ответственность и постоянный контроль на этом участке возлагались на исполнявшего обязанности коменданта и начальника пожарной охраны, начальника штаба курсового дивизиона А. В. Берегового. В то же время отделом кадров ОГПУ в школу направляются кадровые офицеры для замещения вакантных должностей. Среди первых прибывших были: старший руководитель тактики конницы 1-й школы погранохраны и войск ОГПУ А. Н. Стриженов, назначенный на должность помощника начальника штаба школы; А. Н. Поморов, назначенный на должность начальника военно-хозяйственного довольствия. Должность инструктора автодела занял А. Л. Шнейдер. Заведующим финансового довольствия стал Е. М. Чижевский. На должность начальника штаба курсового батальона был назначен А. В. Береговой, а должность начальника части материального обеспечения принял И. Н. Октябрьский\n\nНапряженный труд командиров, политработников, преподавателей, рабочих и служащих по достоинству был оценен руководством ОГПУ. Ко дню пятнадцатой годовщины ВЧК высокие награды получили 67 сотрудников школы. Начальник школы С. И. Абрамович был награжден знаком «Почетный чекист». Начальник штаба Д. Ф. Макаров, помощник начальника школы по политчасти А. Л. Сидоренко, начальник учебной части И. И. Апанасевич, комендант школ С. М. Дайшутов и начальник штаба дивизиона были награждены именным оружием системы Нагана. Именные пистолеты Коровина были вручены командирам дивизионов В. С. Долгову, А. С. Новикову, И. С. Шумскому, начальнику строевого отделения И. Г. Семкину, начальнику химической службы      Н. П. Сосновскому и другим сотрудникам\n\nК середине марта 1933 года строительство зданий первой очереди было закончено. Завершился первый этап становления школы."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок8.png",title:"Штат школы",bio:"Приказом начальника школы № 63 от 15 марта 1933 года объявлялся первый постоянный штат Четвертой школы погранохраны и войск ОГПУ. Данный приказ и последовавшие за ним организационные меры нужно считать вторым этапом формирования Саратовской школы. С точки зрения истории института, это один из самых значимых документов. Ниже приводится первый состав основных подразделений, отделов и служб, сохранившихся как структурные единицы до сегодняшнего дня. Штатом предусматривались два пехотных и один бронетанковый дивизион. Первый дивизион возглавил Т. С. Шумский, начальником штаба был назначен А. Г. Синников, а заместителем командира по политчасти – И. И. Цаплыгин. Кроме этого в дивизионе имелись три должности командира-руководителя. На эти должности были назначены В. А. Данилов, М. Е. Косарев, В. А. Дронов. Третье звено руководителей дивизиона составляли курсовые офицеры взводов. В первом дивизионе ими стали: В. К. Мельдер, М. С. Кожевников, А. В. Масесов, И. И. Барсов и В. Н. Ермолаев. Аналогичным был и штат второго дивизиона. Его командиром стал В. С. Долгов, начальником штаба – Г. С. Барон, заместителем по политической части – А. П. Муничкин. Командирами-руководителями назначены Л. А. Головкин, П. Х. Смолин, И. Д. Ермилов, а курсовыми командирами взводов – П. С. Ведринов, А. С. Зевякин, П. Е. Семенов, Е. М. Шамин и В. Н. Молотов. Таким был первый постоянный состав Саратовского военного института. На командно-преподавательскую работу, как правило, после окончания курсов усовершенствования при Высшей Московской Пограничной школе ОГПУ в числе первых прибыли А. Н. Апполонов,  П. В. Бурмак, К. Г. Войтелев,  В. С. Долгов,  С. И. Иовлев,   И. А. Калинин, А. А. Ковальчук, В. Т. Корепанов, А. Е. Косынкин, Д. В. Крамарчук, С. В. Кузьмин, А. И. Макаров, Ф. Е. Маковецкий, А. Е. Нанакин,  П. В. Прокофьев, В. Г. Чаплыгин, Е. И. Эйдукевич и многие другие. Были созданы циклы артиллерии, социально-экономический, топографии, огневой, тактики пехоты и специальной подготовки. В зависимости от потребности в кадрах сроки обучения на различных отделениях колебались от 1,5 (или от 2,5) до 3 лет.\n\nТретьим этапом становления школы, как учебного заведения, стало ее комплектование переменным составом, т. е. курсантами."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок9.png",title:"Комплектование курсантами",bio:"Прием в военно-учебное заведение осуществлялся в соответствии с приказом ОГПУ от 13 апреля 1932 г. № 320, которым было объявлено «Положение о нормальных школах погранохраны и войск ОГПУ». Согласно этому положению школы состояли при коллегии ОГПУ и подчинялись начальнику отдела кадров ОГПУ с одновременным подчинением по линии военно-строевой подготовки начальнику Главного управления пограничной охраны и войск ОГПУ (ГУПО и ВОГПУ). Школа являлась отдельной чекистско-войсковой частью. Оперативно-боевое использование школы производилось распоряжением коллегии ОГПУ. Руководство учебной работой осуществлялось через группу инспекторов при Инспекции боевой подготовки ГУПО и ВОГПУ. Основной задачей «нормальная» школа имела подготовку лиц среднего начальствующего состава для пограничной охраны и внутренних войск ОГПУ, соответственно, на должности помощника начальника заставы и командира взвода. К каждому командиру, выпущенному школой, предъявлялись следующие требования:\n\n- обладать сильными волевыми качествами и уметь управлять современным сложным боем;\n\n- уметь руководить военно-политической и специальной подготовкой, воспитанием красноармейцев, младшего командного состава и заставы, и взвода в целом;\n\n- обладать необходимыми знаниями и умением для конкретного руководства всеми видами боевой работы красноармейца и вверенного подразделения в целом.\n\nЗа период обучения в школе курсанты должны были в одинаковой мере овладеть знаниями и умениями для командования как в пехотных, так и в кавалерийских частях погранохраны и войск ОГПУ.\n\nПреимущественное право поступления в школу предоставлялось выходцам из семей индустриальных рабочих, членам и кандидатам партии, комсомольцам.\n\nВ школу предполагалось принимать лиц, обладавших подготовкой в объеме начального и семилетнего образования, на добровольных началах. Каждый из прибывших абитуриентов с семилетним образованием обязан был по целевому направлению отработать в сельской местности Саратовского края агитатором-пропагандистом несколько месяцев и с полученной справкой (отзывом-характеристикой) от местных советско-партийных органов возвратиться в школу, где окончательно решался вопрос о его зачислении в курсанты.\n\nПрибытие абитуриентов ожидалось в середине марта 1933 года. Для их приема и предварительной обработки до приемных испытаний назначалась комиссия в составе пяти человек. Председатель – помощник начальника штаба А. Н. Стриженов. Члены комиссии: от хозяйственной части – И. Д. Ильин, медицинский врач        С. М. Рубинчи, от политчасти – помощник командира дивизиона В. И. Целенко и комендант школы        С. М. Дайшутов.\n\nВ своей работе комиссия руководствовалась специально разработанной штабом «Инструкцией по приему и обработке прибывающих курсантов». Ею предусматривалось, что все абитуриенты, поступающие в батальон формирования, разбиваются на группы по десять человек, группы сводятся во взводы по семь групп в каждом, во главе которых становятся курсовые командиры."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок10.png",title:"Начало занятий",bio:"В дивизионе формирования курсанты остаются на все время прохождения приемных испытаний. Из более пятисот человек, зачисленных в курсанты, свыше половины имели образование 4–6 классов. Восемь курсантов были самоучками, и только 232 человека имели семилетнее образование. Преимущественное право поступления предоставлялось коммунистам и комсомольцам.           В числе принятых их было 93 %. Возраст первого набора курсантов был от 22 до 30 лет.\n\n29 апреля 1933 г. в театре имени Н. Г. Чернышевского состоялся торжественный вечер, посвященный началу учебы. А 1 мая 1933 г. представитель Саратовского городского Совета А. В. Сердюков, огласив приказ коллегии ОГПУ № 72 от 27 апреля 1933 года, вручил 4-й школе Боевое знамя Принимавший Боевое знамя начальник-военком школы С. И. Абрамович заверил Советское правительство, что личный состав школы с честью и достоинством будет беречь Красное знамя, как символ воинской чести, доблести и славы и всегда будет готов под этим знаменем выполнить любые задачи по защите завоеваний Великого Октября. Громовым троекратным «ура» ответил коллектив школы на поздравление по случаю вручения знамени. Закончилась торжественная церемония исполнением «Интернационала»\n\n3 мая 1933 года начались плановые занятия по подготовке командиров-организаторов охраны границ. Наряду с пехотным (двухгодичным) штатом предусматривались два трехгодичных отделения – химическое и саперно-маскировочное, в составе которых имелось 4 курсантских пехотных дивизиона, дивизион саперов и химиков. Сформировано два дивизиона пехотного отделения. Каждый дивизион состоял из шести взводов. Взвод делился на две учебные группы. Специальный дивизион включал в себя химическое отделение и саперно-маскировочное отделение. Оба отделения имели по два взвода и две учебные группы в каждом взводе.\n\nУчебные часы на пехотных отделениях в пограншколах распределялись между предметами приблизительно следующим образом: военно-теоретический цикл и чекистская подготовка – 45 %; практика в войсках – 25,3 %; общественно-политический цикл – 14,1 %; общеобразовательный – 13,6 %; резерв – 2 %. В 1931–1932 гг. четко определились количество и объем социально-экономических дисциплин в военных школах. Социально-экономический цикл включал в себя следующие дисциплины: ленинизм – 120 часов; история ВКП(б) – 100; политэкономия – 90; теория советского хозяйства – 90; история Коминтерна – 40; антирелигиозная пропаганда – 30; курс партийно-политической работы – 122 часа. Всего на общественно-политические предметы отводилось 632 часа. Повышению качества учебы в военных школах способствовало выполнение постановлений ЦК ВКП(б) от 25 августа 1932 г. «Об учебных программах и режиме в начальной и средней школе» и ЦИК СССР от 19 сентября 1932 г. «Об учебных программах и режиме в высшей школе и техникумах». Руководствуясь требованиями этих документов, военно-учебные заведения в основном ликвидировали «лабораторно-бригадный метод» в обучении, повысили роль преподавателя в учебном процессе и теоретический уровень преподавания, более целеустремленно стали прививать курсантам навыки самостоятельной работы, добились повышения личной ответственности обучаемых за успеваемость. Для обеспечения учебного процесса в штат школы были включены красноармейские подразделения, кавалерийский взвод, взвод связи, учебная батарея, бронетанковый дивизион и взвод музыкантов."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок11.png",title:"Реорганизация в составе НКВД",bio:"В июне 1934 года, в связи с образованием Народного комиссариата внутренних дел (НКВД), 4-я школа погранохраны и войск ОГПУ была переименована. Она стала называться «4-я пограничная школа НКВД СССР» Приказом НКВД СССР от 11 июля 1934 года № 2 Главное управление пограничной охраны и войск ОГПУ переименовано в Главное управление пограничной и внутренней охраны (ГУПВО) НКВД СССР и введено в состав образованного НКВД СССР.\n\nИзменилась структура учебного процесса, вводились новые учебные дисциплины: стрелковая механика, география, химия и железнодорожное дело. Учебная часть и часть материального обеспечения были реорганизованы в соответствующие отделы. С учетом международной обстановки и потребности войск увеличился набор курсантов, а продолжительность учебы несколько сократилась"},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок12.png",title:"Первые выпуски",bio:"13 октября 1934 года, через полтора года после начала учебы, состоялся первый досрочный выпуск пехотного отделения.\n\n7 ноября 1935 г. был проведен второй (досрочный) выпуск. По времени он совпал с учреждением в пограничных и внутренних войсках персональных воинских званий и соответствовавших званию знаков различия командного, начальствующего и рядового состава. Выпускники 1935 года стали первыми лейтенантами."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок13.png",title:"Предвоенные годы",bio:"Конец 30-х – начало 40-х годов ХХ в. характеризовались резким обострением международной обстановки. Этот период потребовал от правительства страны наращивать военный потенциал, увеличивать численность Вооруженных Сил и войск НКВД. Эти процессы напрямую коснулись Саратовского училища НКВД СССР. В 1938 году на первый курс было зачислено 600 человек. Ни один из семи предыдущих наборов не был столь многочисленным. Комплектование курсантами велось за счет военнослужащих из пограничных, внутренних, железнодорожных, конвойных и промышленных частей, а также военно-строительных подразделений и Красной Армии. С 1939 года на учебу впервые стала приниматься гражданская молодежь. Сокращается число лекций, увеличивается время на самостоятельную работу курсантов, вводится система плановых консультаций. Возросло число полевых практических занятий. Преподавание всех предметов подчинялось принципу «Учить тому, что необходимо на войне».\n\nНа новый, более высокий уровень была поднята массово-культурная и спортивная работа. При училище создается четвертый Райсовет «Динамо».\n\nИз года в год училище повышало свой авторитет в глазах общественности города Саратова и пользовалось заслуженным уважением.\n\nСаратовское военное училище НКВД СССР накануне Великой Отечественной войны накопило опыт подготовки военных кадров, располагало опытными командирами, преподавателями и политработниками. В училище, наряду с подготовкой по специальности, обучали будущих командиров основам общевойскового боя. Еще задолго до войны училище имело опыт подготовки командиров в короткие сроки, а выпускники его – практику боевых действий при защите интересов СССР."},
{photo:"images/фото_СОЗДАНИЕ4-ПШ/фото/Рисунок14.png",title:"Накануне войны",bio:"Например, в 1938 году мужественно сражались с японцами в районе озера Хасан будущий Герой Советского Союза преподаватель училища капитан П. Ф. Терешкин и выпускники нашего училища А. Багров, В. Г. Щекотин, Н. Е. Родин,  К. М. Коврижный, А. Г. Видюлин, награжденные впоследствии медалями.\n\n17 сентября 1939 года Правительство отдало приказ войскам перейти границу и взять под защиту население Западной Белоруссии и Западной Украины, над которым нависла угроза порабощения фашистской Германией (в училище в связи с этим был проведен митинг). И вновь воспитанники училища оказались на линии огня, пополняя ряды командиров пограничных войск.\n\n30 ноября 1939 года началась советско-финская война боевыми действиями на Карельском перешейке. В январе 1940 года в училище был проведен досрочный выпуск командиров-лейтенантов, основная масса которых была направлена на фронт. В тяжелейших боях они вместе с воинами Красной Армии нанесли поражение белофиннам и добились победы. Свой вклад в эту победу внесли выпускники: Д. И. Ракус, В. Г. Трифонов, Мелехин, Козлов, А. К. Константинов и другие. Молодые офицеры с честью выполнили возложенные на них задачи. В представлении к награде лейтенанта Ракус Д.И. говорилось: «… активно участвовал в боях с белофиннами 17 и               19 января 1940 года. Был ранен, но остался в строю и до конца боя руководил своим взводом. Он 57 суток удерживал свой район обороны в блокированном Уомском гарнизоне. Проявил себя стойким бойцом-командиром», за что был удостоен высокого звания Героя Советского Союза (посмертно).\n\nК 1941 году обстановка в мире все более усугублялась и угроза нападения Германии на СССР возрастала. В этой обстановке училище  продолжало выполнять свою главную задачу по подготовке офицерских кадров для пограничных войск и органов НКВД, способных управлять боевыми действиями своих подразделений. Учебный процесс приобретал все более напряженный ритм. Подготовка курсантов осуществлялась в соответствии с требованиями возможной войны. Командование училища, педагоги и курсанты делали все для того, чтобы отлично овладеть знаниями, обеспечить высокое качество выполнения программы обучения и лучше подготовить выпускников к службе в войсках, к защите рубежей Родины."}
];

const CONFLICTS_PAGES = [
{photo:"images/фото_ликвидация/фото/Рисунок 35.png",title:"Обострение межнациональных конфликтов",bio:"Участие личного состава Саратовского военного училища в ликвидации межнациональных конфликтов на территории Советского Союза (конец 1980-х – начало 1990-х гг.).\n\nВ результате обострения проблем социально-экономического и политического характера, а также перестроечных процессов в Советском Союзе в конце 1980-х гг. резко осложнилась обстановка в республиках Закавказья – в Азербайджане и Армении. Этот период ознаменовался усилением националистических и экстремистских движений в республиках. Вспыхнули массовые беспорядки в городах Баку, Сумгаит, Кировабад, Ереван и других населенных пунктах."},
{photo:"images/фото_ликвидация/фото/Рисунок 28.png",title:"Первая командировка — Баку, 1988",bio:"В результате этих столкновений руководством страны было принято решение на участие личного состава Саратовского военного училища в охране общественного порядка и обеспечения общественной безопасности в составе войсковых резервов:\n\nПервая служебная командировка Саратовского военного училища МВД СССР состоялась в город Баку (Азербайджанская ССР). Она продолжалась с 29 февраля по 11 марта 1988 года."},
{photo:"images/фото_ликвидация/фото/Рисунок 29.png",title:"Третья командировка — лето 1988",bio:"Служебная командировка в Ереван продлилась с 22 по 30 марта 1988 года."},
{photo:"images/фото_ликвидация/фото/Рисунок 30.png",title:"Четвёртая командировка — Баку",bio:"третья поездка военнослужащих, оказавшаяся более продолжительной (4–27 июля 1988 г.), напряженной и тяжелой."},
{photo:"images/фото_ликвидация/фото/Рисунок 31.png",title:"Пятая командировка — Фергана",bio:"Четвертая командировка состоялась опять в город Баку (Азербайджанская ССР). Она началась 19 ноября 1988 г., а завершилась лишь 20 января 1989 года. Вместе с тем 1-й батальон курсантов продолжал нести службу в Баку до  16 февраля 1989 года."},
{photo:"images/фото_ликвидация/фото/Рисунок 32.png",title:"Шестая командировка — Сухуми",bio:"Следующий крупный межнациональный конфликт возник в мае–июне 1989 г. на территории Узбекской ССР в Ферганской области. С 4 июня по 17 июля 1989 состоялась пятая командировка военнослужащих Саратовского военного училища МВД СССР в город Фергану (Узбекская ССР)."},
{photo:"images/фото_ликвидация/фото/Рисунок 33.png",title:"Седьмая командировка — НКАО",bio:"17 августа 1989 года 1-й и 4-й батальоны курсантов вылетели из аэропорта Ферганы. Все были уверены, что самолеты направляются в пункт постоянной дислокации в город Саратов. Но уже в полете маршрут изменили и самолеты были направленны в Абхазию. Так началась шестая командировка в город Сухуми (Грузинская ССР). Она продолжалась с 17 июня по 30 июля 1989 года.\n\nСедьмая командировка (Азербайджанская ССР, НКАО, п. Шаумяновск), длившаяся с 6 июня по 31 июля 1990 года."},
{photo:"images/фото_ликвидация/фото/Рисунок 34.png",title:"Итоги и значение",bio:"В дальнейшем (1990–1992 гг.) офицеры и солдаты Саратовского военного училища МВД СССР еще не раз направлялись в служебные командировки в НКАО Азербайджанской ССР.\n\nВ ходе выполнения служебно-боевых задач на территории советского государства Общественный порядок был восстановлен благодаря действиям силовых структур государства и, в частности, усилиями офицеров и курсантов Саратовского высшего военного командного Краснознаменного училища имени Ф. Э. Дзержинского МВД СССР, выполнявших задачи в составе Войскового оперативного резерва. В ходе служебных командировок военнослужащие демонстрировали высокий моральный дух, крепкое чувство товарищества, готовность пожертвовать жизнью, верность военной присяге, ответственность и профессионализм всего личного состава. Они получили колоссальный опыт выполнения задач в экстремальной ситуации по несению патрульно-постовой службы, охране важных государственных объектов, проведению специальных операций по пресечению массовых беспорядков, несению службы на контрольно-пропускных пунктах, эвакуации и защиты беженцев, пресечению противоправных действий преступных элементов, действий в составе маневренной группы и т. д.\n\nПо мнению специалистов, проблема межнациональных отношений на сегодняшний день еще не получила своего оптимального решения, а потому сохраняется вероятность их обострения. Следовательно, повышается роль таких силовых структур, как войска национальной гвардии Российской Федерации."}
];

const MODERN_PAGES = [
{photo:"images/Фото/ФОТО 1.png",title:"Реорганизация после распада СССР",bio:"Распад Советского Союза привел к коренным изменениям во внешней и внутренней политике его правопреемника – Российской Федерации. Это событие не могло не повлиять на все сферы жизни нашей страны, в т. ч. и на ее силовые структуры. Существенным изменениям подверглась организация внутренних войск. Произошли организационно-штатные изменения и в бывшим Саратовском военном училище внутренних войск МВД СССР. 10 февраля 1992 г. на основании приказа МВД России училище стали именовать высшим военным командным Краснознаменным училищем внутренних войск МВД России имени Ф. Э. Дзержинского.\n\nВ 1990-е гг. в стране проводится активное реформирование всех сфер общественной жизни, направленное на обновление страны. Реформы не могли не коснуться такой важнейшей области, как образование. При этом руководство государства провозгласило область образования важнейшим приоритетом государственной политики. В 1991 г. в военное училище был проведен набор курсантов 1 батальона, который начал учиться по переходной 5-летней программе обучения. Его выпуск в количестве 244 офицеров состоялся в 1996 г. по специальности «командная тактическая мотострелковых войск, юриспруденция» с присвоением квалификации «офицер мотострелковых войск с высшим военно-специальным образованием, юрист»."},
{photo:"images/Фото/ФОТО 2.jpg",title:"Северный Кавказ",bio:"Особую страницу в истории военного института занимает Северный Кавказ. В 1993–1995 гг. офицеры военного института принимали участие в обеспечении общественного порядка во Владикавказе. Затем – на территории Чеченской республики. выпускника военного института погибли, выполняя свой воинский долг в далеких чеченских аулах. А начиналось все с Указа Президента Российской Федерации от 30 ноября 1997 г. «О мероприятиях по восстановлению конституционной законности и правопорядка на территории Чеченской республики Вооруженными силами Российской Федерации». Для ликвидации опаснейшего очага экстремистской и террористической напряженности была создана объединенная группировка федеральных войск. Первоначально она насчитывала до 24 тысяч человек, в т. ч. и до 5 тысяч военнослужащих внутренних войск. Всего в чеченских кампаниях участвовало свыше 18 тысяч военнослужащих внутренних войск. Около 10,5 тысяч человек были награждены орденами и медалями. Среди них были и офицеры военного училища. В 1995–1996 гг. в распоряжение командира отдельной дивизии оперативного назначения (ОДОН) на территорию Северного Кавказа отправилось 69 младших офицеров.\n\nС марта 1996 г. в Чеченскую республику направлялись уже старшие офицеры. Всего было откомандировано 108 человек. Около 60 % из них за мужественное выполнение возложенных обязанностей были удостоены высоких государственных наград. В их числе и кавалеры ордена Мужества: И. В. Воронков, Э. В. Горбачев, А. Н. Доскалиев, Д. С. Колотилин, В. Л. Груздев, В. А. Отрыжко, Н. Г. Смирнов, А. А. Шевелев и многие другие. В то же время за годы чеченских компаний  80 бойцов и командиров за свои героические подвиги были навечно зачислены в списки своих воинских частей. 70 военнослужащих внутренних войск были удостоены высокого звания Героя Российской Федерации, 47 из них – посмертно. В числе героев – семь выпускников военного института.\n\nВместе с тем в 2017 г. Приказом Федеральной службы войск национальной гвардии Российской Федерации за мужество и героизм, проявленные в боевых действиях, в списки личного состава военного института были навечно зачислены его выпускники: подполковник Н. В. Мамонов, майоры С. Ю. Дашков, Р. А. Китанин,  старшие лейтенанты М. Ю. Мордовин,  Е. А. Ерошин, лейтенант А. В. Луконин."},
{photo:"images/Фото/ФОТО 3.png",title:"Парады Победы",bio:"1995 г. ознаменовался участием Саратовского военного училища в Параде, посвященном 50-летию Победы советского народа в Великой Отечественной войне в Москве, на Поклонной горе.\n\nВ 2018 и 2019 гг. личный состав 1-го, 4-го и 5-го батальонов снова участвовал в Параде Победы, но уже на Красной Площади. Парадный полк снова возглавлял начальник военного института, но на этот раз генерал-майор С. Д. Мухоед. В очередной раз парадная коробка офицеров и курсантов заслужила высокую оценку своим действиям со стороны начальствующих и правительственных лиц. Не менее высокие отзывы были даны и при выполнении военным институтом конкретных служебно-боевых задач. С 1999 г. военный институт ежегодно выделял личный состав для охраны общественного порядка в Саратове и Саратовской области. Сводные отряды военного института неоднократно направлялись для ликвидации массовых беспорядков и вооруженных преступников в Балашов, Пугачев и Красноармейск."},
{photo:"images/Фото/ФОТО 5.png",title:"Награды и переименования",bio:"22 апреля 2002 г. приказом Министра внутренних дел за большой вклад в дело воспитания и подготовки офицерских кадров институт был награжден памятным Вымпелом Министра внутренних дел.\n\n17 мая 2003 г. на основании приказа Главного командования ВВ МВД России институт начали именовать Саратовским военным институтом внутренних войск МВД России. С 2003 г. выпускниками института начал комплектоваться Президентский полк. Это уникальная воинская часть, занимающаяся обеспечением охраны объектов Московского Кремля – официальной резиденции Президента Российской Федерации – привлекаемая к участию в проведении протокольных мероприятий на высшем государственном уровне, выделению почетных караулов, несению службы у Вечного огня на могиле Неизвестного солдата у Кремлевской стены. Полк входит в состав Федеральной службы охраны Российской Федерации и имеет статус спецслужбы. Полк дислоцируется в Кремле, в здании Арсенала. Кроме охранных функций его личный состав участвует во многих торжественных мероприятиях, проводимых в Кремле, в т. ч. и в инаугураций Президента страны. Подбор кандидатов из числа выпускников военного института для службы в полку проводится очень тщательно. С каждым кандидатом проводится собеседование и специальное тестирование. В числе военнослужащих Президентского полка были следующие выпускники института: лейтенанты С. В. Власов, Д. В. Федоров, В. Н. Цыганок, С. В. Путилов, А. И. Трифонов, А. Д. Краснов, А. А. Евтодиенко, А. В. Николаев, Д. В. Рогозянский и другие."},
{photo:"images/Фото/ФОТО 7.jpg",title:"Новое Боевое Знамя",bio:"28 ноября 2008 г. состоялась церемония вручения военному институту нового Боевого Знамени. На основании приказа МВД России от  15 декабря 2009 г. № 971 военный институт стал называться Саратовским военным институтом внутренних войск Министерства внутренних дел Российской Федерации. В августе 2015 г. институту было возвращено наименование «Краснознаменный». 13 ноября 2015 г. Первый заместитель Министра внутренних дел – Главнокомандующий внутренними войсками МВД России генерал армии В. В. Золотов провел торжественную церемонию прикрепления ордена Боевого Красного Знамени и орденской ленты к знамени военного института. С апреля 2016 г. военный институт становится центром подготовки военнослужащих войск национальной гвардии. В 2016 году В целях обеспечения государственной и общественной безопасности образована Федеральная служба войск национальной гвардии Российской Федерации. Основой новой силовой структуры стали внутренние войска МВД России, которые были преобразованы в войска национальной гвардии Российской Федерации.  На основании приказа Росгвардии от 1 октября 2026 года № 017 военный институт был переименован в Саратовский военный Краснознаменный институт войск национальной гвардии Российской Федерации. 22 марта 2017 г. Указом Президента Российской Федерации он был награжден орденом Жукова."},
{photo:"images/Фото/ФОТО 10.jpg",title:"Чемпионат мира по футболу 2018",bio:"В 2018 г. личный состав  4 батальона курсантов со своими офицерами привлекался для обеспечения общественного порядка в Казани при проведении Чемпионата мира по футболу.\n\n18 мая 2019 года в военном институте состоялось торжественная церемония гашения художественной марки, посвященной Герою России Роману Александровичу Китанину. В мероприятии приняли участие член правления общероссийской организации ветеранов боевых действий генерал-полковник Анатолий Шкирко, врио начальника института полковник Шамиль Вялитов, Герой России Александр Янклович, начальник Управления Росгвардии по Саратовской области Геннадий Макаров, представители областного Правительства и духовенства, родственники и сослуживцы погибшего офицера, а также курсанты, ветераны, военнослужащие и сотрудники ведомства."},
{photo:"images/Фото/ФОТО 12.jpg",title:"Специальная военная операция",bio:"24 февраля 2022 года Президент России Владимир Путин объявил о начале специальной военной операции по защите Донбасса. Ее целью глава государства назвал демилитаризацию и денацификацию Украины.\n\nВойска национальной гвардии совместно с подразделениями российских вооруженных сил выполняют служебно-боевые задачи в ходе специальной военной операции на Украине.\n\nЛичный состав военного института с первых дней, в составе группировок войск принимает непосредственное участие в проведении военных операций по обеспечению общественной безопасности и охране правопорядка, защите населения от преступных посягательств и мародерства в населенных пунктах, освобожденных от националистических вооруженных формирований. За время проведения специальной военной операции выпускники военного института демонстрируют высокий уровень подготовки и боевого мастерства, действуют четко и профессионально, проявляют истинные мужество и героизм. 4 выпускника военного института были удостоены высокого звания Героя России.\n\nОдин из них полковник Белоглазов Александр Михайлович, который в соответствии с Указом Президента РФ был назначен начальником военного института в июле 2024 года, а в 2025 году ему было присвоено звание генерал-майор."},
{photo:"images/Фото/ФОТО 15.jpg",title:"Белоглазов А. М. — начальник института",bio:"Александр Михайлович родился 29 января 1978 года в селе Большой Карай Романовского района Саратовской области. В детстве увлекался спортом. В 1995 году, после окончания сельской Большекарайской средней школы, поступил в Саратовское высшее военное командное Краснознамённое училище внутренних войск МВД России имени Ф. Э. Дзержинского. В 1997 году проходил войсковую стажировку в учебной роте специального назначения в Отдельной дивизии оперативного назначения (ОДОН) имени Ф. Э. Дзержинского, в 1999 году прошёл стажировку в 1-м Краснознамённом отряде специального назначения «Витязь». В 2000 году с отличием окончил Саратовский военный институт и сдал норматив на право ношения крапового берета. Служил в Отдельной дивизии оперативного назначения на офицерских должностях в отряде специального назначения «Витязь». С 2021 года являлся его командиром. Принимал участие в боевых командировках на Кавказе, Сирии и Украине. С приходом в военный институт профессионала военного дела такого уровня, учебный процесс военного института начал видоизменяться в корне. Практическая работа курсантов в должности командира взвода на учебных занятиях стала наиболее максимально приближена к боевой. Спортивная часть жизнидеятельности курсантов явилась одним из основных приоритетов в обучении Сборные команды по различным видам спорта являются постоянным участниками и победителя соревнований как областного так и федерального значения. Так С 13 по 15 ноября 2025 года в Саратове прошли Всероссийские соревнования по боксу среди военнослужащих «Защитник», а также первый чемпионат России по дисциплине бокса «Удар на силу».\n\nБолее пяти тысяч гостей стали свидетелями зрелищных поединков и насыщенной программы турнира.  В течение трёх дней работала выставка военной техники, именитые спортсмены проводили автограф-сессии и мастер-классы, а выступления творческих коллективов стали ярким украшением соревнований. В рамках праздника бокса у Вечного огня в Парке Победы прошла торжественная церемония возложения цветов, а на территории рядом с Протон-Ареной были высажены липы. В мероприятиях приняли участие организаторы соревнований, руководители военных учебных заведений и почётные гости. В результате напряженных боев военнослужащие военного института заняли 3 место в весовых категориях 75 кг, 86 кг и 92 кг, а Егор Свойкин стал чемпионом Всероссийского турнира по боксу в весовой категории 63,5 кг."},
{photo:"images/Фото/ФОТО 16.jpg",title:"Военно-патриотическое воспитание",bio:"Огромное внимание уделяется военно-патриотическому воспитанию подрастающему поколению во взаимодействии с подавляющим большинством образовательных учреждений города и области. Боевой опыт начальника военного института и личная примерность стала основным методом обучения и воспитания будущих «офицеров – Дзержинцев».\n\nВ октябре 2024 года личный состав военного института по решению Директора войск национальной гвардии – Главнокомандующего войсками национальной гвардии Героем России генералом армии В.В. Золотова принимал участие в обеспечении общественной безопасности XVI саммита БРИКС в городе Казань. Командиром тактической группы был назначен заместитель начальника военного института полковник Мерзеликин Роман Сергеевич. В результате грамотного управления, слаженной и профессиональной работы личного состава тактической группы в зоне ее ответственности грубых нарушений общественного порядка и чрезвычайных происшествий,  не допущено. Руководством войск была дана высокая оценка деятельности тактической группы военного института. По завершении мероприятия командующий Приволжским округом Росгвардии генерал-полковник Сергей Просяник от имени руководства Росгвардии, командования Приволжского округа и руководства Республики Татарстан поблагодарил командиров подразделений и в их лице - весь личный состав за достойное и безупречное выполнение задач по участию в обеспечении безопасности саммита БРИКС в городе Казани."},
{photo:"images/Фото/ФОТО 18.jpg",title:"Инженерное обеспечение",bio:"За истекший период с 2024 года, значительно активизировалось инженерное обеспечение служебно-боевой деятельности и учебных задач образовательного процесса. Служба находится в готовности к обучению специалистов по постановке и уничтожению взрывных устройств. Упорядочилась правовая работа. Одновременно увеличился комплекс задач по подготовке военных специалистов. Творческий подход к планированию образовательного процесса, согласование программ между кафедрами, изыскание резерва учебного времени для более глубокого обучения военным дисциплинам курсантов, продуманная организация обучения курсантов перед выпуском вносят серьезный вклад в профессиональную подготовку выпускников. Воинский уклад жизни, привитие любви к военной форме одежды, строевая выучка и выправка каждого курсанта, четкая организация контроля стали составной частью образовательного и воспитательного процесса по формированию командирских качеств будущих офицеров."},
{photo:"images/Фото/ФОТО 19.jpg",title:"Учебно-материальная база",bio:"Интересам образовательной деятельности подчинена разветвленная учебно-материальная база. В пункте постоянной дислокации военного института имеются: специализированные классы и методические кабинеты кафедр – 68; учебные классы – 3; лекционные залы – 4; лаборатории – 2; типография; телестудия; учебно-опытная мастерская; методический кабинет военного института; центр автоматизированной системы управления; переоборудованный и усовершенствованный в соответствии с требованиями новых Общевоинских уставов РФ строевой плац; обновленный тир со стрелковым городком; спортивный корпус и вновь созданные тренажерный зал и зал борьбы; полностью обновленный в результате проведенного капитального ремонта учебный корпус; клуб; спортивный городок с полосой препятствий; реконструированный караул № 1 с караульным двориком. Полевая учебно-материальная база находится в учебном центре. На сегодняшний день занятия по военно-профессиональным дисциплинам проводятся в 13 специализированных классах войскового стрельбища, на учебных объектах: «КПП в районе ЧП», «Застава», «КПП по пропуску людей на ВГО», «КПП по пропуску автотранспорта на ВГО», на инженерном городке, городке РХБЗ, гранатометном городке, участке для метания ручных оборонительных и наступательных гранат. В учебном центре имеется строевой плац, а также тактическое поле с элементами танкодрома, участком для обкатки личного состава боевой техникой и другие уставные инженерные элементы, используемые при ведении различных видов боя. Военный институт имеет солидную тренажерную базу, которая включает в себя: тренажер по обучению и подготовке водителей; тренажер по обучению меткой стрельбе из стрелкового оружия; динамический тренажер по обучению механика-водителя БМП; стрелковый тренажер SCATT для обучения стрельбе из ПМ. База общевоенной и физической подготовки включает в себя: стрелковый тир со стрелковым городком; спортивный зал; 3 гимнастических городка; вновь созданные зал борьбы и тренажерный зал; 3 стрелковых городка, 2 футбольные площадки (для минифутбола), 2 полосы препятствий; 3 строевых плаца, оборудованных в соответствии с требованиями новых общевоинских уставов; караульный городок и класс по подготовке караулов и внутреннего наряда к несению службы.\n\nТенденции развития образовательного процесса позволяют утверждать, что состояние учебно-методического, информационного и библиотечного обеспечения дают возможность качественно осуществлять теоретическую подготовку будущих офицеров. Вместе с тем приоритетными направлениями деятельности командования военного института сегодня продолжает оставаться решение следующих задач: 1) плановое обновление командного, профессорско-преподавательского, учебно-вспомогательного состава и качественный отбор абитуриентов. Критериями для ее решения должны были стать боевой и служебный опыт офицеров. научный потенциал преподавателей, компетентность всех работников и всесторонний анализ качеств кандидатов в курсанты; 2) реконструкция имеющейся и создание новой современной приказарменной и полевой учебно-лабораторной базы. Переоборудование и переоформление учебных, жилых помещений и внутренней территории института. Внедрение в сознание, жизнь и быт всех категорий военнослужащих «культа чистоты и воинского порядка»; 3) резкое укрепление воинской, учебной, трудовой и исполнительской дисциплины во всех звеньях и структурах института. Повышение требовательности к положению дел на закрепленных участках работы и всестороннее стимулирование эффективного труда; 4) активизация форм, способов и методов образовательного процесса, его интенсивности и практической направленности, всестороннего методического обеспечения, тщательного изучения и распространения передового опыта; 5) повышение действенности воспитательных мероприятий, пропаганда идеологии патриотизма, норм нравственности и здорового образа жизни, популяризация физической культуры и спорта, уважительного отношения к традициям и педагогическому опыту старших поколений «Офицеров - Саратовцев».\n\nПоступательное развитие военного института, четкое обозначение и решение перспектив, повышение потенциала качества подготовки офицерских кадров – суть ежедневной заботы действующего начальника военного института."},
{photo:"images/Фото/ФОТО 20.jpg",title:"",bio:"Целых девять десятилетий отделяют нас от памятного дня 19 мая 1932 года, когда была вписана первая строка в историю Саратовского военного ордена Жукова Краснознаменного института войск национальной гвардии Российской Федерации. Военный институт все эти годы высоко держал и держит честь и достоинство войск национальной гвардии. Боевые традиции умножались в ратных делах курсантов и офицеров-выпускников.\n\nВ труднейших условиях становления военного института личный состав проявил высокий энтузиазм, героизм и самоотверженность, создавая необходимые условия для обучения и воспитания будущих «Офицеров-Дзержинцев».\n\nЗа многие годы из стен военного института вышли тысячи высококвалифицированных, в совершенстве знающих свое дело защитников Отечества.\n\nС момента образования и до наших дней военный институт прошел долгий путь становления и развития. Менялись названия, организационная структура, количественный состав, но неизменным оставалось высокое качество подготовки высококвалифицированных офицерских кадров для войск правопорядка. На современном этапе выпускники военного института благодаря приобретенному багажу знаний, умений и навыков востребованы не только в войсках национальной гвардии но и в других силовых структурах и ведомствах.\n\nИстория военного института продолжается, умножается добрыми делами во имя настоящего и будущего нашей Родины. Пройдут годы, из стен военного института выйдут новые поколения офицеров для войск национальной гвардии России. Люди с высоким чувством ответственности, беззаветно преданные народу, квалифицированные военные специалисты. Они, несомненно, впишут новые яркие страницы в героическую летопись Саратовского военного института.\n\nСаратовский военный институт Росгвардии – это не только место, где получают знания, это источник, откуда курсанты черпают умение правильно, умело, интересно жить, ревностно служить народу и Отечеству.\n\nПоступив в старейшую кузницу офицерских кадров войск национальной гвардии ты не только начнешь обучение военному делу, но и сделаешь главный шаг в своей жизни, связав свою судьбу с исторической правопреемственностью и вековой традицией по защите Российского государства.\n\nГоды, проведенные в стенах военного института, – это не только лекции, семинары, практические занятия и учения, не только процесс познания, это еще и школа становления настоящего мужского характера, правильного мировоззрения и стойкости духа настоящего патриота своего Отечества. В каких бы регионах страны ни служили наши выпускники, им никогда не забыть курсантской поры. И каждый год те, кто уезжает после выпуска в войска национальной гвардии, увозят с собой вместе с дипломом и нагрудным знаком военного института благодарную память о родном месте, которое им дало путевку в достойную жизнь."}
];